export function usePayment(config: PaymentProviderConfig) {
  const [status, setStatus] = useState<PaymentStatus>('idle');
  const [error, setError] = useState<PaymentError | null>(null);
  const [walletSupport, setWalletSupport] = useState<Record<WalletType, boolean>>({
    apple_pay: false,
    google_pay: false,
  });
  const [lastResult, setLastResult] = useState<PaymentResult | null>(null);

  const initialized = useRef(false);

  const initialize = useCallback(async () => {
    try {
      setStatus('initializing');
      setError(null);
      await PaymentService.initialize(config);
      const [applePay, googlePay] = await Promise.all([
        Platform.OS === 'ios' ? PaymentService.isWalletSupported('apple_pay') : Promise.resolve(false),
        Platform.OS === 'android' ? PaymentService.isWalletSupported('google_pay') : Promise.resolve(false),
      ]);
      setWalletSupport({
        apple_pay: applePay,
        google_pay: googlePay,
      });
      initialized.current = true;
      setStatus('ready');
      return true;
    } catch (e: any) {
      const err = e instanceof PaymentError ? e : new PaymentError(e?.message || 'Initialization failed');
      setError(err);
      setStatus('failed');
      return false;
    }
  }, [config]);

  useEffect(() => {
    initialize();
  }, [initialize]);

  useEffect(() => {
    if (!emitter) return;
    const subs = [
      emitter.addListener('PaymentSuccess', (event: PaymentResult) => {
        setLastResult(event);
        setStatus('completed');
      }),
      emitter.addListener('PaymentFailure', (event: PaymentResult) => {
        setLastResult(event);
        setError(new PaymentError(event?.errorMessage || 'Payment failed', event?.errorCode));
        setStatus('failed');
      }),
      emitter.addListener('PaymentCancelled', () => {
        setStatus('cancelled');
      }),
    ];
    return () => {
      subs.forEach(s => s.remove());
    };
  }, []);

  const processWalletPayment = useCallback(
    async (request: WalletPaymentRequest) => {
      try {
        setStatus('processing');
        setError(null);
        const walletType: WalletType = Platform.OS === 'ios' ? 'apple_pay' : 'google_pay';
        const result = await PaymentService.processWalletPayment(walletType, request);
        setLastResult(result);
        setStatus(result.success ? 'completed' : 'failed');
        if (!result.success) {
          throw new PaymentError(result.errorMessage || 'Wallet payment failed', result.errorCode);
        }
        return result;
      } catch (e: any) {
        const err = e instanceof PaymentError ? e : new PaymentError(e?.message || 'Wallet payment failed');
        setError(err);
        setStatus('failed');
        throw err;
      }
    },
    []
  );

  const purchaseProduct = useCallback(async (request: InAppPurchaseRequest) => {
    try {
      setStatus('processing');
      setError(null);
      const result = await PaymentService.purchaseInAppProduct(request);
      setLastResult(result);
      setStatus(result.success ? 'completed' : 'failed');
      if (!result.success) {
        throw new PaymentError(result.errorMessage || 'Purchase failed', result.errorCode);
      }
      return result;
    } catch (e: any) {
      const err = e instanceof PaymentError ? e : new PaymentError(e?.message || 'Purchase failed');
      setError(err);
      setStatus('failed');
      throw err;
    }
  }, []);

  const restore = useCallback(async () => {
    try {
      setStatus('processing');
      setError(null);
      const result = await PaymentService.restorePurchases();
      setStatus('ready');
      return result;
    } catch (e: any) {
      const err = e instanceof PaymentError ? e : new PaymentError(e?.message || 'Restore failed');
      setError(err);
      setStatus('failed');
      throw err;
    }
  }, []);

  return {
    status,
    error,
    lastResult,
    walletSupport,
    initialized: initialized.current,
    initialize,
    processWalletPayment,
    purchaseProduct,
    restore,
  };
}

type PaymentButtonProps = {
  title: string;
  onPress: () => Promise<void> | void;
  loading?: boolean;
  disabled?: boolean;
  testID?: string;
};

export function PaymentButton({
  title,
  onPress,
  loading,
  disabled,
  testID,
}: PaymentButtonProps) {
  return (
    <TouchableOpacity
      testID={testID}
      style={[styles.button, disabled && styles.buttonDisabled]}
      onPress={() => onPress()}
      disabled={disabled || loading}
      activeOpacity={0.8}
    >
      {loading ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>{title}</Text>}
    </TouchableOpacity>
  );
}

type PaymentSheetProps = {
  config: PaymentProviderConfig;
  item: PurchaseItem;
  merchantName: string;
  countryCode: string;
  onSuccess?: (result: PaymentResult) => void;
  onFailure?: (error: PaymentError) => void;
};

export function PaymentSheet({
  config,
  item,
  merchantName,
  countryCode,
  onSuccess,
  onFailure,
}: PaymentSheetProps) {
  const { status, error, lastResult, walletSupport, processWalletPayment, purchaseProduct, restore } =
    usePayment(config);

  useEffect(() => {
    if (status === 'completed' && lastResult?.success) {
      onSuccess?.(lastResult);
    }
  }, [status, lastResult, onSuccess]);

  useEffect(() => {
    if (error) {
      onFailure?.(error);
    }
  }, [error, onFailure]);

  const canUseWallet = useMemo(() => {
    return Platform.OS === 'ios' ? walletSupport.apple_pay : walletSupport.google_pay;
  }, [walletSupport]);

  const handleWalletPayment = useCallback(async () => {
    try {
      await processWalletPayment({
        amount: item.price,
        currency: item.currency,
        countryCode,
        merchantName,
        label: item.title,
      });
      Alert.alert('Success', 'Wallet payment completed.');
    } catch (e: any) {
      Alert.alert('Payment Failed', e?.message || 'Unable to complete wallet payment.');
    }
  }, [processWalletPayment, item, countryCode, merchantName]);

  const handleInAppPurchase = useCallback(async () => {
    try {
      await purchaseProduct({
        productId: item.id,
        quantity: 1,
      });
      Alert.alert('Success', 'In-app purchase completed.');
    } catch (e: any) {
      Alert.alert('Purchase Failed', e?.message || 'Unable to complete purchase.');
    }
  }, [purchaseProduct, item]);

  const handleRestore = useCallback(async () => {
    try {
      await restore();
      Alert.alert('Restored', 'Purchases restored successfully.');
    } catch (e: any) {
      Alert.alert('Restore Failed', e?.message || 'Unable to restore purchases.');
    }
  }, [restore]);

  const loading = status === 'initializing' || status === 'processing';

  return (
    <View style={styles.container}>
      <Text style={styles.title}>{item.title}</Text>
      {!!item.description && <Text style={styles.description}>{item.description}</Text>}
      <Text style={styles.price}>
        {item.currency} {item.price.toFixed(2)}
      </Text>

      {canUseWallet && (
        <PaymentButton
          title={Platform.OS === 'ios' ? 'Pay with Apple Pay' : 'Pay with Google Pay'}
          onPress={handleWalletPayment}
          loading={loading}
          disabled={loading}
          testID="wallet-payment-button"
        />
      )}

      <PaymentButton
        title="Buy In-App"
        onPress={handleInAppPurchase}
        loading={loading}
        disabled={loading}
        testID="iap-payment-button"
      />

      <PaymentButton
        title="Restore Purchases"
        onPress={handleRestore}
        loading={false}
        disabled={loading}
        testID="restore-purchases-button"
      />

      <Text style={styles.status}>Status: {status}</Text>
      {!!error && <Text style={styles.error}>{error.message}</Text>}
    </View>
  );
}

